import{_ as i,C as r,o as a,c as n,a0 as s,b as c,w as o,a as l,E as d,a1 as p}from"./chunks/framework.DZNqfkJl.js";const v=JSON.parse('{"title":"Configuración y Arquitectura del Backend","description":"","frontmatter":{},"headers":[],"relativePath":"backend.md","filePath":"backend.md"}'),u={name:"backend.md"};function h(g,e,m,k,b,C){const t=r("Mermaid");return a(),n("div",null,[e[1]||(e[1]=s('<h1 id="configuracion-y-arquitectura-del-backend" tabindex="-1">Configuración y Arquitectura del Backend <a class="header-anchor" href="#configuracion-y-arquitectura-del-backend" aria-label="Permalink to &quot;Configuración y Arquitectura del Backend&quot;">​</a></h1><p>El backend de <strong>Structo</strong> está desarrollado en <strong>.NET 10</strong> utilizando C#. Sigue los principios de la <strong>Arquitectura Limpia (Clean Architecture)</strong> y <strong>N-Capas</strong> para asegurar un código mantenible, testeable y desligado de las tecnologías externas.</p><h2 id="🚀-como-levantar-el-entorno-local" tabindex="-1">🚀 Cómo levantar el entorno local <a class="header-anchor" href="#🚀-como-levantar-el-entorno-local" aria-label="Permalink to &quot;🚀 Cómo levantar el entorno local&quot;">​</a></h2><h3 id="_1-preparacion-de-base-de-datos" tabindex="-1">1. Preparación de Base de Datos <a class="header-anchor" href="#_1-preparacion-de-base-de-datos" aria-label="Permalink to &quot;1. Preparación de Base de Datos&quot;">​</a></h3><p>Asegúrate de tener corriendo tus bases de datos (SQL Server y MongoDB). Puedes levantar los contenedores usando el archivo <code>docker-compose.yml</code> (si dispones de él en la raíz o carpeta <code>docker/</code>):</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker-compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><p>O usar tus instancias locales. Asegúrate de configurar las cadenas de conexión correctas en los archivos <code>appsettings.Development.json</code> dentro del proyecto principal.</p><h3 id="_2-ejecutar-migraciones-entity-framework" tabindex="-1">2. Ejecutar Migraciones (Entity Framework) <a class="header-anchor" href="#_2-ejecutar-migraciones-entity-framework" aria-label="Permalink to &quot;2. Ejecutar Migraciones (Entity Framework)&quot;">​</a></h3><p>Entra al proyecto backend. Puedes aplicar las migraciones a la base de datos SQL Server de dos maneras:</p><ul><li><strong>Opción 1: Usando los scripts (Recomendado)</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./ef.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span></span></code></pre></div></li><li><strong>Opción 2: Usando <code>dotnet</code> tradicional</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ef</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> database</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.Infrastructure/Structo.Infrastructure.csproj</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --startup-project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div></li></ul><h3 id="_3-cargar-datos-iniciales-seed" tabindex="-1">3. Cargar Datos Iniciales (Seed) <a class="header-anchor" href="#_3-cargar-datos-iniciales-seed" aria-label="Permalink to &quot;3. Cargar Datos Iniciales (Seed)&quot;">​</a></h3><p>El proyecto backend está configurado para ejecutar el proceso de <em>Seeding</em> de datos de forma <strong>automática</strong> cada vez que se levanta la aplicación. Durante el arranque (<code>Program.cs</code>), si existen entidades base faltantes, el sistema las insertará por su cuenta usando <code>InitDatabase</code>.</p><h3 id="_4-correr-el-proyecto" tabindex="-1">4. Correr el Proyecto <a class="header-anchor" href="#_4-correr-el-proyecto" aria-label="Permalink to &quot;4. Correr el Proyecto&quot;">​</a></h3><p>Al igual que las migraciones, tienes dos alternativas para levantar la Web API:</p><ul><li><strong>Opción 1: Usando los scripts (Recomendado)</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./dev.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span></span></code></pre></div></li><li><strong>Opción 2: Usando <code>dotnet</code> tradicional</strong><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> src/Structo.WebApi/Structo.WebApi.csproj</span></span></code></pre></div></li></ul><p>El servidor de desarrollo iniciará y deberías poder acceder a la interfaz interactiva de la API (Swagger) navegando a:</p><ul><li><code>http://localhost:5000/swagger</code> o</li><li><code>https://localhost:5001/swagger</code> (si usaste el comando de <code>dev.sh run</code> con perfil HTTPS activo).</li></ul><hr><h2 id="🛠️-listado-de-comandos-de-ayuda-scripts-automaticos" tabindex="-1">🛠️ Listado de Comandos de Ayuda (Scripts Automáticos) <a class="header-anchor" href="#🛠️-listado-de-comandos-de-ayuda-scripts-automaticos" aria-label="Permalink to &quot;🛠️ Listado de Comandos de Ayuda (Scripts Automáticos)&quot;">​</a></h2><p>Para facilitar el flujo, el repositorio expone dos scripts <code>.sh</code> en la raíz del backend:</p><h3 id="script-dev-sh" tabindex="-1">Script <code>dev.sh</code> <a class="header-anchor" href="#script-dev-sh" aria-label="Permalink to &quot;Script `dev.sh`&quot;">​</a></h3><p>Envuelve la interfaz de línea de comandos de .NET agregando la configuración por defecto y el perfil HTTPS.</p><ul><li><code>./dev.sh run</code>: Ejecuta la aplicación con el perfil HTTPS.</li><li><code>./dev.sh watch</code>: Ejecuta la aplicación con Hot Reload (watch) habilitado.</li><li><code>./dev.sh build</code>: Compila la solución completa.</li><li><code>./dev.sh build-errors</code>: Compila mostrando únicamente los errores de compilación.</li><li><code>./dev.sh test</code>: Ejecuta todos los tests automáticos encontrados (Unidad e Integración).</li><li><code>./dev.sh clean</code>: Limpia la solución compilada.</li><li><code>./dev.sh restore</code>: Restaura todos los paquetes NuGet.</li></ul><h3 id="script-ef-sh" tabindex="-1">Script <code>ef.sh</code> <a class="header-anchor" href="#script-ef-sh" aria-label="Permalink to &quot;Script `ef.sh`&quot;">​</a></h3><p>Envuelve <code>dotnet ef</code> pre-estableciendo los nombres correctos de los proyectos de Infraestructura y WebApi.</p><ul><li><code>./ef.sh add &lt;nombre&gt;</code>: Añade una nueva migración.</li><li><code>./ef.sh update</code>: Aplica las migraciones pendientes en la base de datos.</li><li><code>./ef.sh remove</code>: Revierte y elimina la última migración.</li><li><code>./ef.sh list</code>: Lista todas las migraciones existentes.</li></ul><hr><h2 id="🏗️-patrones-de-diseno-utilizados" tabindex="-1">🏗️ Patrones de Diseño Utilizados <a class="header-anchor" href="#🏗️-patrones-de-diseno-utilizados" aria-label="Permalink to &quot;🏗️ Patrones de Diseño Utilizados&quot;">​</a></h2><p>Durante el desarrollo del backend, se promueve el uso de los siguientes patrones arquitectónicos:</p><ul><li><strong>Inyección de Dependencias (DI)</strong>: Utilizado orgánicamente en .NET Core para inyectar servicios en controladores y otros servicios, promoviendo el bajo acoplamiento.</li><li><strong>Repository Pattern</strong>: Abstracción de acceso a datos provista por las interfaces en el <code>Domain</code> y su implementación en la capa de <code>Infrastructure</code>.</li><li><strong>Data Transfer Objects (DTO)</strong>: Aislando completamente la capa de controladores y los modelos de dominio.</li><li><strong>CQRS (Opcional, según complejidad)</strong>: Separación ligera entre lectura y mutación manejada en la capa de servicios.</li></ul><h2 id="📁-estructura-de-proyectos-n-capas" tabindex="-1">📁 Estructura de Proyectos (N-Capas) <a class="header-anchor" href="#📁-estructura-de-proyectos-n-capas" aria-label="Permalink to &quot;📁 Estructura de Proyectos (N-Capas)&quot;">​</a></h2><p>La solución (<code>Structo.sln</code>) y el directorio <code>src/</code> están divididos conceptualmente:</p>',32)),(a(),c(p,null,{default:o(()=>[d(t,{id:"mermaid-193",class:"mermaid",graph:"graph%20TD%0A%20%20%20%20API%5BStructo.WebApi%5CnCapa%20de%20Presentaci%C3%B3n%5D%20--%3E%20S%5BStructo.Services%5CnL%C3%B3gica%20de%20Aplicaci%C3%B3n%5D%0A%20%20%20%20API%20--%3E%20DTO%5BStructo.DTO%5CnContratos%20de%20Datos%5D%0A%20%20%20%20S%20--%3E%20DOM%5BStructo.Domain%5CnReglas%20de%20Negocio%20%2F%20Entidades%5D%0A%20%20%20%20S%20--%3E%20INF%5BStructo.Infrastructure%5CnAcceso%20a%20Datos%20%2F%20EF%20Core%5D%0A%20%20%20%20INF%20--%3E%20DOM%0A%20%20%20%20API%20-.%20Inyecta%20.-%3E%20INF%0A%20%20%20%20%0A%20%20%20%20style%20API%20fill%3A%232a70d9%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20S%20fill%3A%230b8a4f%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A%20%20%20%20style%20INF%20fill%3A%23d9702a%2Cstroke%3A%23333%2Cstroke-width%3A2px%2Ccolor%3A%23fff%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[l(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=s('<h3 id="descripcion-de-las-capas" tabindex="-1">Descripción de las Capas <a class="header-anchor" href="#descripcion-de-las-capas" aria-label="Permalink to &quot;Descripción de las Capas&quot;">​</a></h3><ol><li><strong>Structo.WebApi</strong>: Contiene los Controladores (Endpoints HTTP), la configuración del host y el registro de la inyección de dependencias (<code>Program.cs</code>). Responsable de recibir las consultas y delvolver DTOs.</li><li><strong>Structo.Services</strong>: Contiene la lógica de aplicación. Coordina cómo la aplicación interactúa con la base de datos a través de las interfaces y aplica reglas de negocio a gran escala, orquestando mapeos entre Entidades de Dominio y DTOs.</li><li><strong>Structo.Domain</strong>: Es el núcleo del sistema. Contiene las Entidades (modelos de tabla), Enums, Interfaces core y lógica de negocio pura de forma estricta. <strong>No depende de ningún otro proyecto de la solución</strong>.</li><li><strong>Structo.Infrastructure</strong>: Contiene las clases de <code>DbContext</code> (Entity Framework), las implementaciones reales de los repositorios y la configuración hacia bases de datos externas (SQL Server / MongoDB). Depende de <code>Structo.Domain</code>.</li><li><strong>Structo.DTO</strong>: Contiene estructuras planas que transportan los datos solicitados hacia el exterior de la API, evitando exponer directamente las clases del Dominio.</li><li><strong>Structo.Common</strong>: Constantes transversales, excepciones personalizadas compartidas y métodos de extensión para toda la solución.</li></ol>',2))])}const f=i(u,[["render",h]]);export{v as __pageData,f as default};
